sql_query:
SELECT SUM(ss.ss_sales_price * ss.ss_quantity) AS total_sales_revenue
FROM store_sales AS ss
WHERE ss.ss_sales_price IS NOT NULL AND ss.ss_quantity IS NOT NULL;

SELECT COALESCE(SUM(sr.sr_return_amt), 0) AS total_returns
FROM store_returns AS sr
WHERE sr.sr_return_amt IS NOT NULL;

SELECT DISTINCT s.s_store_name
FROM store AS s
ORDER BY s.s_store_name;
